# Mean |SHAP| ranking across repeats/folds (lightweight TEST) -------------------

rank_rf  <- compute_mean_shap_ranking(nested_rep_tbl, "rf",  repeats_to_use = 1:10, seed = .seed_shap_reg,
                                      nsim = 100, bg_n = 100, test_subsample = NULL, topk = 30) %>% mutate(model = "rf")

rank_xgb <- compute_mean_shap_ranking(nested_rep_tbl, "xgb", repeats_to_use = 1:10, seed = .seed_shap_reg,
                                      nsim = 100, bg_n = 100, test_subsample = NULL, topk = 30) %>% mutate(model = "xgb")

rank_knn  <- compute_mean_shap_ranking(nested_rep_tbl, "knn",  repeats_to_use = 1:10, seed = .seed_shap_reg,
                                       nsim = 100, bg_n = 100, test_subsample = NULL, topk = 30) %>% mutate(model = "knn")

rank_svm  <- compute_mean_shap_ranking(nested_rep_tbl, "svmRadial",  repeats_to_use = 1:10, seed = .seed_shap_reg,
                                       nsim = 100, bg_n = 100, test_subsample = NULL, topk = 30) %>% mutate(model = "svmRadial")


# Combine all rankings --------------------------------------

ml_colors <- c(
  "RF"        = "#C96A1B",  # dark orange
  "XGB"       = "#E28E2C",  # mid orange
  "SVM"       = "#3F6F63",  # darker green-gray
  "KNN"       = "#7FA69A",  # mid green-gray
  "GLM"       = "#4C6FA1"  # muted blue
  #"NfL alone" = "gray25",
)


variable_labels <- unlist(T1label_bio)

# --- Normalization and overall ordering ---
rank_all <- dplyr::bind_rows(rank_rf, rank_xgb, rank_knn, rank_svm) %>%
  dplyr::mutate(mean_abs_shap_raw = mean_abs_shap) %>%
  # Within-model normalization
  dplyr::group_by(model) %>%
  dplyr::mutate(mean_abs_shap_norm = mean_abs_shap / sum(mean_abs_shap, na.rm = TRUE)) %>%
  dplyr::ungroup() %>%
  # Overall ordering by mean normalized SHAP
  dplyr::group_by(feature) %>%
  dplyr::mutate(all_mean_abs_shap = mean(mean_abs_shap_norm, na.rm = TRUE)) %>%
  dplyr::ungroup() %>%
  # Model factor - normalize svmRadial to svm
  dplyr::mutate(
    model = tolower(as.character(model)),
    model = ifelse(model == "svmradial", "svm", model),
    model = factor(model, levels = c("knn", "svm", "xgb", "rf")),
    model = dplyr::recode(model,
                          "knn" = "KNN",
                          "svm" = "SVM",
                          "rf"  = "RF",
                          "xgb" = "XGB")
  ) %>%
  dplyr::arrange(dplyr::desc(all_mean_abs_shap))

rank_all


# arranged for RF ranking --------------------------------------

rank_all_rf <- rank_all %>%
  dplyr::filter(model == "RF") %>%
  dplyr::arrange(dplyr::desc(mean_abs_shap_norm)) %>%
  dplyr::mutate(rank_rf = dplyr::row_number())

rank_all <- rank_all %>%
  dplyr::left_join(
    rank_all_rf %>%
      dplyr::select(feature, rank_rf),
    by = "feature"
  ) %>%
  dplyr::arrange(desc(rank_rf)) %>%
  dplyr::mutate(feature = factor(feature, levels = unique(feature)))

rank_all

## Plot mean |SHAP| ranking across models ---------------

SuppleFig_SHAP_slope <- ggplot(rank_all, #%>% filter(model %in% c("RF","XGB")), 
                               aes(x = feature, 
                                   y = mean_abs_shap_norm, fill = model)) +
  geom_col(position = "dodge", alpha = 0.8) +
  coord_flip() +
  # Apply variable labels
  scale_x_discrete(labels = function(x) ifelse(x %in% names(variable_labels), variable_labels[x], x)) +
  # Apply color mapping
  scale_fill_manual(
    values = ml_colors,
    breaks = c("KNN", "SVM", 
               "XGB", "RF"),  # control legend order
    labels = c("KNN", "SVM", 
               "XGB", "RF")
  ) +
  labs(
    title = "(B) Feature importance for ALSFRS-R slope prediction",
    subtitle = "Normalised SHAP values across nested cross-validation repeats and folds",
    x = NULL, 
    y = "Normalised |SHAP| (relative contribution)",
    fill = "Model",
  ) +
  theme_bw(base_size = 16) +
  theme(legend.position = "bottom",
        plot.title = element_text(size = 18, face = "bold"),
        plot.subtitle = element_text(size = 14))

SuppleFig_SHAP_slope

SuppleFigS11B <- SuppleFig_SHAP_slope


